SELECT CD_DIV , CD_DIV_NM , CD_CODE , CD_CODE_NM FROM cd_common WHERE USE_YN = 'Y'
AND CD_DIV = #{cdDiv}
AND CD_CODE = #{cdCode}

SELECT CD_DIV , CD_DIV_NM , CD_CODE , CD_CODE_NM , CD_VALUE_1 FROM cd_common WHERE USE_YN = 'Y'
AND CD_DIV = #{cdDiv}
ORDER BY CD_SORT

SELECT *
FROM CD_COMMON
WHERE USE_YN = 'Y'
AND CD_DIV = #{cdDiv}

    AND CD_CODE != #{excludeAuth}

ORDER BY CD_CODE
